def build_expected_audit_event(
    *,
    action: str,
    outcome: str,
    outcome_desc: str,
    device_id: str,
    resource_type: str = "Observation",
) -> dict[str, Any]:
    """
    Build the minimal expected shape of a FHIR AuditEvent.

    action  : "C" (create) | "R" (read) …
    outcome : "0" (success) | "8" (serious failure)
    """
    return {
        "resourceType": "AuditEvent",
        "type": {
            "system": "http://dicom.nema.org/resources/ontology/DCM",
            "code": "110110",
            "display": "Patient Record",
        },
        "action": action,
        "outcome": outcome,
        "outcomeDesc": outcome_desc,
        "agent": [
            {
                "who": {"reference": f"Device/{device_id}"},
                "requestor": True,
            }
        ],
        "entity": [
            {
                "type": {
                    "system": "http://terminology.hl7.org/CodeSystem/audit-entity-type",
                    "code": "2",
                    "display": "System Object",
                },
                "what": {"type": resource_type},
            }
        ],
    }


def assert_audit_event_shape(
    audit_payload: dict[str, Any],
    *,
    expected_outcome: str,
    expected_device_id: str,
    expected_action: str = "C",
) -> None:
    """Assert mandatory AuditEvent fields are present and correct."""
    assert audit_payload["resourceType"] == "AuditEvent", "resourceType must be AuditEvent"
    assert audit_payload.get("action") == expected_action, f"Expected action={expected_action}"
    assert audit_payload.get("outcome") == expected_outcome, (
        f"Expected outcome={expected_outcome}, got {audit_payload.get('outcome')}"
    )
    agents = audit_payload.get("agent", [])
    assert len(agents) >= 1, "AuditEvent must have at least one agent"
    agent_refs = [a.get("who", {}).get("reference", "") for a in agents]
    assert any(expected_device_id in ref for ref in agent_refs), (
        f"Expected device {expected_device_id} in agent refs {agent_refs}"
    )
    assert "recorded" in audit_payload, "AuditEvent must contain a 'recorded' timestamp"
    assert "entity" in audit_payload, "AuditEvent must reference an entity"


