class TestRegisteredDeviceIngest:
    """Registered devices must be able to push Observations successfully."""

    @respx.mock
    @freeze_time(FIXED_NOW)
    def test_observation_accepted_returns_201(
        self,
        http_client: httpx.Client,
        valid_observation: dict[str, Any],
        registered_device: dict[str, Any],
    ) -> None:
        """POST /ingest/Observation with a registered device → 201 Created."""
        # --- arrange ---
        respx.get(f"{DEVICE_ENDPOINT}/{REGISTERED_DEVICE_ID}").mock(
            return_value=httpx.Response(200, json=registered_device)
        )
        created_obs = {**valid_observation, "id": str(uuid.uuid4())}
        respx.post(INGEST_ENDPOINT).mock(
            return_value=httpx.Response(201, json=created_obs)
        )
        # Audit sink
        audit_route = respx.post(AUDIT_ENDPOINT).mock(
            return_value=httpx.Response(201, json={"resourceType": "AuditEvent"})
        )

        # --- act ---
        response = http_client.post(
            "/ingest/Observation",
            json=valid_observation,
            headers={"X-Device-ID": REGISTERED_DEVICE_ID},
        )

        # --- assert ---
        assert response.status_code == 201
        body = response.json()
        assert body["resourceType"] == "Observation"
        assert body["status"] == "final"

