class TestAuditEventEmission:
    """An AuditEvent must be emitted for every operation, success or failure."""

    @respx.mock
    @freeze_time(FIXED_NOW)
    def test_audit_event_emitted_on_successful_ingest(
        self,
        http_client: httpx.Client,
        valid_observation: dict[str, Any],
        registered_device: dict[str, Any],
    ) -> None:
        """Successful ingest → AuditEvent with outcome='0'."""
        respx.get(f"{DEVICE_ENDPOINT}/{REGISTERED_DEVICE_ID}").mock(
            return_value=httpx.Response(200, json=registered_device)
        )
        respx.post(INGEST_ENDPOINT).mock(
            return_value=httpx.Response(201, json=valid_observation)
        )
        audit_route = respx.post(AUDIT_ENDPOINT).mock(
            return_value=httpx.Response(201, json={})
        )

        http_client.post(
            "/ingest/Observation",
            json=valid_observation,
            headers={"X-Device-ID": REGISTERED_DEVICE_ID},
        )

        assert audit_route.called, "AuditEvent endpoint was never called"
        audit_request_body = json.loads(audit_route.calls.last.request.content)
        assert_audit_event_shape(
            audit_request_body,
            expected_outcome="0",
            expected_device_id=REGISTERED_DEVICE_ID,
        )

